import React, { useState } from 'react'
import useData from './data';
import { useTableContext } from './Provider';
import { pageLimit } from './data';
function InfiniteScroll({children}) {
  const [skipResult,setSkipResult] = useState(0)
  const { loading, error, tableData, total, skip } = useData(skipResult);
  const [hasMore, setHasMore] = useState(false)
  const { setTableData } = useTableContext()
  useEffect(() => {
   if(tableData && skip) {
      setTableData(tableData)
      setSkipResult(skip + pageLimit)
   }
  },[tableData,skip])
    return (
        <>
        {children}
        </>
    )
}

export default InfiniteScroll
